function SpectraLogoInner({ size = 40, animate = false }: LogoProps) {
  const reactId = React.useId().replace(/:/g, "");
  const theme = getTheme(getThemeName());
 
  const animationStyle = animate
    ? `
      @keyframes spectra-spin-${reactId} {
        0%   { transform: rotate(0deg) scale(1); }
        25%  { transform: rotate(180deg) scale(1); }
        35%  { transform: rotate(180deg) scale(1.06); }
        45%  { transform: rotate(180deg) scale(1); }
        50%  { transform: rotate(180deg) scale(1); }
        75%  { transform: rotate(360deg) scale(1); }
        85%  { transform: rotate(360deg) scale(1.06); }
        95%  { transform: rotate(360deg) scale(1); }
        100% { transform: rotate(360deg) scale(1); }
      }
    `
    : "";
 
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 200 200"
      xmlns="http://www.w3.org/2000/svg"
      style={
        animate
          ? { animation: `spectra-spin-${reactId} 2.4s linear infinite` }
          : undefined
      }
    >
      {animate && <style>{animationStyle}</style>}
      <defs>
        <clipPath id={`spectra-circle-${reactId}`}>
          <circle cx="100" cy="100" r="92" />
        </clipPath>
        <clipPath id={`spectra-s-clip-${reactId}`}>
          <circle cx="100" cy="100" r="82" />
        </clipPath>
      </defs>
 
      {/* Two-tone circle */}
      <circle cx="100" cy="100" r="92" fill={theme.logoTop} />
      <rect
        x="0"
        y="100"
        width="200"
        height="100"
        fill={theme.logoBot}
        clipPath={`url(#spectra-circle-${reactId})`}
      />
 
      <circle
        cx="100"
        cy="100"
        r="92"
        fill="none"
        stroke="rgba(255,255,255,0.08)"
        strokeWidth="1.5"
      />
 
      <g clipPath={`url(#spectra-s-clip-${reactId})`}>
        <path d={S_PATH} fill="white" />
      </g>
    </svg>
  );
}
 
// Memoize: skip re-renders when props haven't changed.
// Main win is static logos in the sidebar/header that were
// re-rendering on every parent state change.
export const SpectraLogo = React.memo(SpectraLogoInner);